public class Command {
    interface Cmd { void execute(); }
    static int value = 0;
    public static void main(String[] args) {
        Cmd add5 = () -> value += 5;
        Cmd mul2 = () -> value *= 2;
        java.util.Deque<Cmd> queue = new java.util.ArrayDeque<>();
        queue.add(add5);
        queue.add(mul2);
        queue.add(add5);
        for (Cmd c : queue) c.execute();
        System.out.println(value);
    }
}
